# Step 14 — Frontend Implementation

> **Goal**: Build the Next.js UI that consumes the backend API. The focus here is on handling the SSE stream to create a compelling, transparent "Agent Trace" UI, and rendering the final structured JSON report into a beautiful dashboard.

---

## 1. State Management (Zustand)

We use Zustand to manage the state of the research session. This state is updated in real-time as SSE events arrive.

```typescript
// src/lib/stores/research-store.ts
import { create } from 'zustand';
import { ResearchReport, SSEEvent } from '@/lib/types/research';

interface ResearchState {
  sessionId: string | null;
  ticker: string | null;
  status: 'IDLE' | 'STARTING' | 'RUNNING' | 'COMPLETED' | 'FAILED';

  // Real-time agent trace
  events: SSEEvent[];
  currentStepIndex: number;

  // Final output
  report: ResearchReport | null;
  error: string | null;

  // Actions
  startSession: (ticker: string) => Promise<void>;
  processSSEEvent: (event: SSEEvent) => void;
  reset: () => void;
}

export const useResearchStore = create<ResearchState>((set, get) => ({
  sessionId: null,
  ticker: null,
  status: 'IDLE',
  events: [],
  currentStepIndex: 0,
  report: null,
  error: null,

  startSession: async (ticker: string) => {
    set({ status: 'STARTING', ticker, events: [], report: null, error: null });
    try {
      const res = await fetch('/api/research', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ticker })
      });
      const data = await res.json();
      set({ sessionId: data.session_id, status: 'RUNNING' });
    } catch (error) {
      set({ status: 'FAILED', error: 'Failed to initialize session' });
    }
  },

  processSSEEvent: (event: SSEEvent) => {
    set((state) => {
      // Append to event log
      const updatedEvents = [...state.events, event];

      // Update state based on event type
      if (event.type === 'session.completed' && event.payload.report) {
        return { events: updatedEvents, status: 'COMPLETED', report: event.payload.report };
      }
      if (event.type === 'session.error') {
        return { events: updatedEvents, status: 'FAILED', error: event.payload.error };
      }

      return { events: updatedEvents, currentStepIndex: state.currentStepIndex + 1 };
    });
  },

  reset: () => set({ sessionId: null, ticker: null, status: 'IDLE', events: [], report: null })
}));
```

---

## 2. Consuming the SSE Stream (React Hook)

This hook connects to the backend stream endpoint and feeds events into our Zustand store.

```typescript
// src/hooks/use-sse-stream.ts
import { useEffect, useRef } from 'react';
import { useResearchStore } from '@/lib/stores/research-store';
import { SSEEvent } from '@/lib/types/research';

export function useSSEStream() {
  const { sessionId, status, processSSEEvent } = useResearchStore();
  const eventSourceRef = useRef<EventSource | null>(null);

  useEffect(() => {
    // Only connect if we have an active running session
    if (status !== 'RUNNING' || !sessionId) {
      if (eventSourceRef.current) {
        eventSourceRef.current.close();
        eventSourceRef.current = null;
      }
      return;
    }

    // Connect to the Next.js BFF proxy which proxies to FastAPI
    const sse = new EventSource(`/api/research/${sessionId}/stream`);
    eventSourceRef.current = sse;

    sse.onmessage = (event) => {
      try {
        const parsed: SSEEvent = JSON.parse(event.data);
        processSSEEvent(parsed);

        // Close connection if agent is done
        if (parsed.type === 'session.completed' || parsed.type === 'session.error') {
          sse.close();
        }
      } catch (err) {
        console.error("Failed to parse SSE event", err);
      }
    };

    sse.onerror = (error) => {
      console.error("SSE Connection Error", error);
      // In production, implement retry backoff here
      sse.close();
    };

    return () => {
      if (eventSourceRef.current) {
        eventSourceRef.current.close();
      }
    };
  }, [sessionId, status, processSSEEvent]);
}
```

---

## 3. The "Agent Trace" Component

This is a critical UX element. Instead of a blank loading screen, we show the user exactly what the AI is doing, step-by-step.

```tsx
// src/components/research/agent-trace.tsx
import { useResearchStore } from '@/lib/stores/research-store';
import { CheckCircle2, CircleDashed, Loader2 } from 'lucide-react';
import { Card } from '@/components/ui/card';

export function AgentTrace() {
  const { events, status } = useResearchStore();

  if (status !== 'RUNNING' && status !== 'STARTING') return null;

  return (
    <Card className="w-full max-w-2xl mx-auto p-6 bg-zinc-950 border-zinc-800 shadow-xl">
      <div className="flex items-center gap-3 mb-6">
        <Loader2 className="h-5 w-5 text-emerald-500 animate-spin" />
        <h3 className="text-lg font-medium text-zinc-100">AI Agent Executing Research</h3>
      </div>

      <div className="space-y-4">
        {events.map((event, index) => {
          const isLatest = index === events.length - 1;

          return (
            <div key={index} className="flex gap-4 opacity-100 transition-opacity">
              <div className="mt-1">
                {isLatest && status === 'RUNNING' ? (
                  <CircleDashed className="h-5 w-5 text-emerald-400 animate-spin" />
                ) : (
                  <CheckCircle2 className="h-5 w-5 text-zinc-500" />
                )}
              </div>

              <div>
                <p className={`text-sm font-medium ${isLatest ? 'text-zinc-200' : 'text-zinc-500'}`}>
                  {getEventLabel(event.type)}
                </p>
                {event.payload?.tool && (
                  <p className="text-xs text-zinc-400 font-mono mt-1">
                    > Executing tool: {event.payload.tool}
                  </p>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </Card>
  );
}

// Helper to translate backend events into UI labels
function getEventLabel(type: string): string {
  switch (type) {
    case 'session.started': return 'Initializing research session...';
    case 'agent.planning': return 'Formulating data gathering strategy...';
    case 'tool.calling': return 'Fetching data from external sources...';
    case 'tool.result': return 'Analyzing retrieved data...';
    case 'agent.synthesizing': return 'Synthesizing final research report...';
    case 'session.completed': return 'Report generation complete.';
    default: return 'Processing...';
  }
}
```

---

## 4. Report Rendering Component

Once `status === 'COMPLETED'`, we render the structured report using shadcn/ui components.

```tsx
// src/components/report/report-view.tsx
import { useResearchStore } from '@/lib/stores/research-store';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';

export function ReportView() {
  const { report, ticker } = useResearchStore();

  if (!report) return null;

  return (
    <div className="w-full max-w-5xl mx-auto space-y-8 animate-in fade-in duration-700">

      {/* Header */}
      <div className="flex justify-between items-end border-b border-zinc-800 pb-6">
        <div>
          <h1 className="text-4xl font-bold text-white tracking-tight">{ticker}</h1>
          <p className="text-zinc-400 mt-2">{report.company_overview}</p>
        </div>
        <Badge variant={report.recommendation === 'BUY' ? 'default' : 'secondary'} 
               className="text-lg px-4 py-1">
          {report.recommendation}
        </Badge>
      </div>

      {/* Executive Summary */}
      <Card className="bg-zinc-900 border-zinc-800">
        <CardHeader>
          <CardTitle className="text-emerald-400">Executive Summary</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-zinc-300 leading-relaxed">{report.executive_summary}</p>
        </CardContent>
      </Card>

      {/* Grid: Financials & Risks */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

        {/* Financial Highlights */}
        <Card className="bg-zinc-900 border-zinc-800">
          <CardHeader>
            <CardTitle>Financial Highlights</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {report.financial_highlights.map((metric, i) => (
                <div key={i} className="flex justify-between items-center border-b border-zinc-800 pb-2">
                  <span className="text-zinc-400">{metric.metric_name}</span>
                  <div className="text-right">
                    <span className="block font-medium text-white">{metric.value}</span>
                    <span className="text-xs text-emerald-500">{metric.context}</span>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>

        {/* Risks */}
        <Card className="bg-zinc-900 border-zinc-800">
          <CardHeader>
            <CardTitle className="text-rose-400">Risk Assessment</CardTitle>
          </CardHeader>
          <CardContent>
            <ul className="space-y-3">
              {report.risks.map((risk, i) => (
                <li key={i} className="flex items-start gap-2 text-sm text-zinc-300">
                  <span className={`px-2 py-0.5 rounded text-[10px] font-bold ${
                    risk.severity === 'High' ? 'bg-rose-500/20 text-rose-400' : 'bg-amber-500/20 text-amber-400'
                  }`}>
                    {risk.severity}
                  </span>
                  {risk.description}
                </li>
              ))}
            </ul>
          </CardContent>
        </Card>
      </div>

      {/* Disclaimer */}
      <p className="text-xs text-zinc-600 text-center mt-12">
        Disclaimer: This report was generated by an AI Agent. It is for informational purposes only and does not constitute financial advice.
      </p>
    </div>
  );
}
```

