import { Router, Request, Response } from 'express';
import Session from '../models/Session';
import Report from '../models/Report';
import { runAgentFlow } from '../agent/graph';

const router = Router();

// POST /api/v1/research
router.post('/', async (req: Request, res: Response) => {
  try {
    const { ticker, query } = req.body;

    if (!ticker || typeof ticker !== 'string') {
      return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Ticker is required' } });
    }

    const session = new Session({ ticker: ticker.toUpperCase(), query });
    await session.save();

    res.status(202).json({
      session_id: session._id,
      ticker: session.ticker,
      status: session.status,
      message: 'Session created. Connect to /stream.'
    });
  } catch (error) {
    console.error('Error starting research:', error);
    res.status(500).json({ error: { code: 'INTERNAL_ERROR', message: 'Failed to start research session' } });
  }
});

// GET /api/v1/research/:id
router.get('/:id', async (req: Request, res: Response) => {
  try {
    const report = await Report.findOne({ sessionId: req.params.id });
    if (!report) {
      return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Report not found' } });
    }
    res.status(200).json(report);
  } catch (error) {
    res.status(500).json({ error: { code: 'INTERNAL_ERROR', message: 'Error fetching report' } });
  }
});

// GET /api/v1/research/:id/stream
router.get('/:id/stream', async (req: Request, res: Response) => {
  try {
    const session = await Session.findById(req.params.id);
    if (!session || session.status !== 'PENDING') {
      return res.status(400).json({ error: { code: 'INVALID_SESSION', message: 'Invalid or already started session' } });
    }

    // Set headers for SSE
    res.setHeader('Content-Type', 'text/event-stream');
    res.setHeader('Cache-Control', 'no-cache');
    res.setHeader('Connection', 'keep-alive');
    res.flushHeaders();

    // Mark as running
    session.status = 'RUNNING';
    await session.save();

    // Send initial event
    res.write(`data: ${JSON.stringify({ type: 'session.started', payload: { ticker: session.ticker } })}\n\n`);

    // Run LangGraph Agent
    try {
      await runAgentFlow(session, res);

      // Update session status when done
      session.status = 'COMPLETED';
      await session.save();

      res.write(`data: ${JSON.stringify({ type: 'session.completed' })}\n\n`);
    } catch (agentError: any) {
      console.error('Agent execution error:', agentError);
      session.status = 'FAILED';
      session.errorMessage = agentError.message;
      await session.save();
      res.write(`data: ${JSON.stringify({ type: 'session.error', error: agentError.message })}\n\n`);
    } finally {
      res.end();
    }
  } catch (error) {
    console.error('Error in stream endpoint:', error);
    res.status(500).end();
  }
});

export default router;

import { Annotation } from '@langchain/langgraph';

export const AgentState = Annotation.Root({
  ticker: Annotation<string>({
    reducer: (x, y) => y ?? x,
  }),
  query: Annotation<string | undefined>({
    reducer: (x, y) => y ?? x,
  }),
  companyProfile: Annotation<any>({
    reducer: (x, y) => y ?? x,
  }),
  stockData: Annotation<any>({
    reducer: (x, y) => y ?? x,
  }),
  financials: Annotation<any>({
    reducer: (x, y) => y ?? x,
  }),
  news: Annotation<any[]>({
    reducer: (x, y) => y ?? x,
  }),
  plan: Annotation<string>({
    reducer: (x, y) => y ?? x,
  }),
  riskAssessment: Annotation<string>({
    reducer: (x, y) => y ?? x,
  }),
  report: Annotation<any>({
    reducer: (x, y) => y ?? x,
  }),
  stepCount: Annotation<number>({
    reducer: (state, update) => state + update,
    default: () => 0,
  }),
});

export type StateType = typeof AgentState.State;

import yahooFinance from 'yahoo-finance2';

export async function fetchStockData(ticker: string) {
  try {
    const quote = await yahooFinance.quote(ticker);
    return quote;
  } catch (error: any) {
    return { error: error.message };
  }
}

export async function fetchCompanyProfile(ticker: string) {
  try {
    const quoteSummary = await yahooFinance.quoteSummary(ticker, { modules: ['assetProfile', 'defaultKeyStatistics'] });
    return quoteSummary;
  } catch (error: any) {
    return { error: error.message };
  }
}

export async function fetchNews(ticker: string) {
  try {
    const search = await yahooFinance.search(ticker, { newsCount: 5 });
    return search.news;
  } catch (error: any) {
    return { error: error.message };
  }
}

import { StateGraph, END, START } from '@langchain/langgraph';
import { ChatOpenAI } from '@langchain/openai';
import { AgentState, StateType } from './state';
import { fetchStockData, fetchCompanyProfile, fetchNews } from './tools';
import { z } from 'zod';
import { Response } from 'express';
import Report from '../models/Report';

// Define the Pydantic-equivalent Zod schema for the final report
const ReportSchema = z.object({
  executiveSummary: z.string(),
  companyOverview: z.string(),
  recommendation: z.enum(['BUY', 'HOLD', 'SELL']),
  confidenceLevel: z.enum(['HIGH', 'MEDIUM', 'LOW']),
  financialAnalysis: z.string(),
  risks: z.array(z.string()),
  bullCase: z.array(z.string()),
  bearCase: z.array(z.string())
});

const llm = new ChatOpenAI({ modelName: 'gpt-4o-mini', temperature: 0.2 });
const synthesizerLlm = new ChatOpenAI({ modelName: 'gpt-4o', temperature: 0.2 }).withStructuredOutput(ReportSchema);

async function planNode(state: StateType) {
  return { plan: `Researching ${state.ticker}`, stepCount: 1 };
}

async function gatherNode(state: StateType) {
  const [stockData, profile, news] = await Promise.all([
    fetchStockData(state.ticker),
    fetchCompanyProfile(state.ticker),
    fetchNews(state.ticker)
  ]);
  return { stockData, companyProfile: profile, news, stepCount: 1 };
}

async function synthesizeNode(state: StateType) {
  const prompt = `Synthesize an investment report for ${state.ticker}.
  Data: ${JSON.stringify({ stock: state.stockData, profile: state.companyProfile, news: state.news }).substring(0, 5000)}
  Provide a professional investment analysis highlighting risks, bull/bear cases, and financial overview.`;

  const report = await synthesizerLlm.invoke(prompt);
  return { report, stepCount: 1 };
}

const workflow = new StateGraph(AgentState)
  .addNode('planner', planNode)
  .addNode('gatherer', gatherNode)
  .addNode('synthesizer', synthesizeNode)
  .addEdge(START, 'planner')
  .addEdge('planner', 'gatherer')
  .addEdge('gatherer', 'synthesizer')
  .addEdge('synthesizer', END);

export const graph = workflow.compile();

export async function runAgentFlow(session: any, res: Response) {
  const initialState = { ticker: session.ticker, query: session.query };

  // Execute and stream events
  for await (const event of await graph.streamEvents(initialState, { version: 'v2' })) {
    const kind = event.event;
    if (kind === 'on_chain_start') {
      if (event.name === 'planner') {
        res.write(`data: ${JSON.stringify({ type: 'agent.planning' })}\n\n`);
      } else if (event.name === 'gatherer') {
        res.write(`data: ${JSON.stringify({ type: 'tool.calling' })}\n\n`);
      } else if (event.name === 'synthesizer') {
        res.write(`data: ${JSON.stringify({ type: 'agent.synthesizing' })}\n\n`);
      }
    }
  }

  // In a real app we can use the result from streamEvents, but here we just invoke to get final state safely
  const finalState = await graph.invoke(initialState);

  const report = new Report({
    sessionId: session._id,
    ticker: session.ticker,
    recommendation: finalState.report.recommendation,
    confidenceLevel: finalState.report.confidenceLevel,
    content: finalState.report
  });
  await report.save();
}

import { create } from 'zustand';

export interface SSEEvent {
  type: string;
  payload?: any;
  error?: string;
}

export interface ResearchReport {
  executiveSummary: string;
  companyOverview: string;
  recommendation: 'BUY' | 'HOLD' | 'SELL';
  confidenceLevel: 'HIGH' | 'MEDIUM' | 'LOW';
  financialAnalysis: string;
  risks: string[];
  bullCase: string[];
  bearCase: string[];
}

interface ResearchState {
  sessionId: string | null;
  ticker: string | null;
  status: 'IDLE' | 'STARTING' | 'RUNNING' | 'COMPLETED' | 'FAILED';
  events: SSEEvent[];
  report: ResearchReport | null;
  error: string | null;

  startSession: (ticker: string) => Promise<void>;
  processSSEEvent: (event: SSEEvent) => void;
  fetchReport: (id: string) => Promise<void>;
  reset: () => void;
}

export const useResearchStore = create<ResearchState>((set, get) => ({
  sessionId: null,
  ticker: null,
  status: 'IDLE',
  events: [],
  report: null,
  error: null,

  startSession: async (ticker: string) => {
    set({ status: 'STARTING', ticker, events: [], report: null, error: null });
    try {
      const res = await fetch('http://localhost:8000/api/v1/research', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ticker })
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error?.message || 'Failed to start');

      set({ sessionId: data.session_id, status: 'RUNNING' });
    } catch (error: any) {
      set({ status: 'FAILED', error: error.message });
    }
  },

  processSSEEvent: (event: SSEEvent) => {
    set((state) => {
      const updatedEvents = [...state.events, event];

      if (event.type === 'session.completed') {
        get().fetchReport(state.sessionId!);
        return { events: updatedEvents, status: 'COMPLETED' };
      }
      if (event.type === 'session.error') {
        return { events: updatedEvents, status: 'FAILED', error: event.error || 'Agent Error' };
      }

      return { events: updatedEvents };
    });
  },

  fetchReport: async (id: string) => {
    try {
      const res = await fetch(`http://localhost:8000/api/v1/research/${id}`);
      const data = await res.json();
      if (res.ok && data.content) {
        set({ report: data.content });
      }
    } catch (error) {
      console.error("Failed to fetch final report", error);
    }
  },

  reset: () => set({ sessionId: null, ticker: null, status: 'IDLE', events: [], report: null, error: null })
}));

import { useEffect, useRef } from 'react';
import { useResearchStore, SSEEvent } from '../store/researchStore';

export function useSSEStream() {
  const { sessionId, status, processSSEEvent } = useResearchStore();
  const eventSourceRef = useRef<EventSource | null>(null);

  useEffect(() => {
    if (status !== 'RUNNING' || !sessionId) {
      if (eventSourceRef.current) {
        eventSourceRef.current.close();
        eventSourceRef.current = null;
      }
      return;
    }

    const sse = new EventSource(`http://localhost:8000/api/v1/research/${sessionId}/stream`);
    eventSourceRef.current = sse;

    sse.onmessage = (event) => {
      try {
        const parsed: SSEEvent = JSON.parse(event.data);
        processSSEEvent(parsed);

        if (parsed.type === 'session.completed' || parsed.type === 'session.error') {
          sse.close();
        }
      } catch (err) {
        console.error("Failed to parse SSE event", err);
      }
    };

    sse.onerror = (error) => {
      console.error("SSE Connection Error", error);
      sse.close();
    };

    return () => {
      if (eventSourceRef.current) {
        eventSourceRef.current.close();
      }
    };
  }, [sessionId, status, processSSEEvent]);
}

