import mongoose from 'mongoose';

const researchSessionSchema = new mongoose.Schema(
  {
    ticker: {
      type: String,
      required: true,
      trim: true,
      uppercase: true,
    },
    query: {
      type: String,
      default: null,
    },
    status: {
      type: String,
      enum: ['PENDING', 'RUNNING', 'COMPLETED', 'FAILED'],
      default: 'PENDING',
    },
    error_message: {
      type: String,
      default: null,
    },
  },
  { timestamps: true }
);

export default mongoose.model('ResearchSession', researchSessionSchema);

import mongoose from 'mongoose';

const researchReportSchema = new mongoose.Schema(
  {
    session_id: {
      type: mongoose.Schema.Types.ObjectId,
      ref: 'ResearchSession',
      required: true,
    },
    ticker: {
      type: String,
      required: true,
    },
    recommendation: {
      type: String,
      enum: ['BUY', 'HOLD', 'SELL'],
      required: true,
    },
    confidence_level: {
      type: String,
      enum: ['HIGH', 'MEDIUM', 'LOW'],
      required: true,
    },
    content: {
      type: mongoose.Schema.Types.Mixed, // Storing the structured JSON output natively
      required: true,
    },
  },
  { timestamps: true }
);

export default mongoose.model('ResearchReport', researchReportSchema);

import express from 'express';
import {
  startResearch,
  getReport,
  streamResearch,
} from '../controllers/researchController.js';

const router = express.Router();

router.post('/', startResearch);
router.get('/:id', getReport);
router.get('/:id/stream', streamResearch);

export default router;

import ResearchSession from '../models/ResearchSession.js';
import ResearchReport from '../models/ResearchReport.js';
// import { buildGraph } from '../agent/graph.js'; // Will implement soon

export const startResearch = async (req, res) => {
  try {
    const { ticker, query } = req.body;
    if (!ticker) {
      return res.status(400).json({ error: 'Ticker is required' });
    }

    const session = await ResearchSession.create({ ticker, query });

    res.status(202).json({
      session_id: session._id,
      ticker: session.ticker,
      status: session.status,
      message: 'Session created. Connect to /stream.',
    });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
};

export const getReport = async (req, res) => {
  try {
    const report = await ResearchReport.findOne({ session_id: req.params.id });
    if (!report) {
      return res.status(404).json({ error: 'Report not found' });
    }
    res.json(report);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
};

export const streamResearch = async (req, res) => {
  const sessionId = req.params.id;

  try {
    const session = await ResearchSession.findById(sessionId);
    if (!session || session.status !== 'PENDING') {
      res.write(`data: ${JSON.stringify({ error: 'Invalid session' })}\n\n`);
      return res.end();
    }

    session.status = 'RUNNING';
    await session.save();

    res.setHeader('Content-Type', 'text/event-stream');
    res.setHeader('Cache-Control', 'no-cache');
    res.setHeader('Connection', 'keep-alive');
    res.flushHeaders();

    // Stub for now. We will hook up LangGraph.js here next.
    res.write(`data: ${JSON.stringify({ type: 'session.started', payload: { ticker: session.ticker } })}\n\n`);

    setTimeout(() => {
      res.write(`data: ${JSON.stringify({ type: 'tool.calling', payload: { tool: 'mock_tool' } })}\n\n`);
    }, 1000);

    setTimeout(() => {
      res.write(`data: ${JSON.stringify({ type: 'session.completed', payload: { report: { executive_summary: 'Mock Report' } } })}\n\n`);
      res.end();
    }, 3000);

  } catch (error) {
    res.write(`data: ${JSON.stringify({ type: 'session.error', payload: { error: error.message } })}\n\n`);
    res.end();
  }
};

import { Annotation } from '@langchain/langgraph';

// Define the state schema using LangGraph Annotation
export const AgentState = Annotation.Root({
  sessionId: Annotation.String,
  ticker: Annotation.String,
  query: Annotation.String,

  stepCount: Annotation({
    reducer: (x, y) => x + y,
    default: () => 0,
  }),

  errors: Annotation({
    reducer: (x, y) => x.concat(y),
    default: () => [],
  }),

  companyProfile: Annotation.Any,
  stockPriceData: Annotation.Any,
  financialStatements: Annotation.Any,
  newsData: Annotation.Any,
  peerData: Annotation.Any,

  researchPlan: Annotation.String,
  riskAssessment: Annotation.String,

  finalReport: Annotation.Any,
  isComplete: Annotation.Boolean,
});

import yahooFinance from 'yahoo-finance2';

export const getFinancialStatements = async (ticker) => {
  try {
    const quote = await yahooFinance.quote(ticker);
    const quoteSummary = await yahooFinance.quoteSummary(ticker, {
      modules: ['financialData', 'defaultKeyStatistics']
    });

    return {
      status: 'success',
      data: {
        price: quote.regularMarketPrice,
        currency: quote.currency,
        financialData: quoteSummary.financialData,
        keyStatistics: quoteSummary.defaultKeyStatistics
      }
    };
  } catch (error) {
    console.error(`Error fetching financials for ${ticker}:`, error);
    return { status: 'error', message: error.message, data: null };
  }
};

import { getFinancialStatements } from '../tools/yahooFinance.js';
import { ChatOpenAI } from '@langchain/openai';
import { z } from 'zod';
import { SYNTHESIS_SYSTEM_PROMPT } from '../prompts/synthesizer.js';
import { HumanMessage, SystemMessage } from '@langchain/core/messages';

// Zod Schema for strict structured output
const ReportSchema = z.object({
  executive_summary: z.string(),
  company_overview: z.string(),
  financial_highlights: z.array(z.object({
    metric_name: z.string(),
    value: z.string(),
    context: z.string()
  })),
  risks: z.array(z.object({
    risk_type: z.string(),
    description: z.string(),
    severity: z.enum(['High', 'Medium', 'Low'])
  })),
  bull_case: z.array(z.string()),
  bear_case: z.array(z.string()),
  recommendation: z.enum(['BUY', 'HOLD', 'SELL']),
  confidence_level: z.enum(['HIGH', 'MEDIUM', 'LOW'])
});

export const inputValidator = async (state) => {
  return { stepCount: 1 };
};

export const researchPlanner = async (state) => {
  return { researchPlan: 'Plan generated', stepCount: 1 };
};

export const dataGatherer = async (state) => {
  const financials = await getFinancialStatements(state.ticker);
  return {
    financialStatements: financials.status === 'success' ? financials.data : null,
    stepCount: 1
  };
};

export const riskAssessor = async (state) => {
  return { riskAssessment: 'Risk evaluated', stepCount: 1 };
};

export const reportSynthesizer = async (state) => {
  const llm = new ChatOpenAI({ modelName: 'gpt-4o-mini', temperature: 0.2 });
  const structuredLlm = llm.withStructuredOutput(ReportSchema, { name: 'ResearchReport' });

  const dataContext = JSON.stringify({
    financials: state.financialStatements,
    risk: state.riskAssessment
  });

  const sysPrompt = SYNTHESIS_SYSTEM_PROMPT.replace('{ticker}', state.ticker).replace('{data_context}', dataContext);

  try {
    const report = await structuredLlm.invoke([
      new SystemMessage(sysPrompt),
      new HumanMessage(`Generate the research report for ${state.ticker}`)
    ]);
    return { finalReport: report, stepCount: 1 };
  } catch (err) {
    console.error('Synthesis failed:', err);
    return { errors: [err.message], stepCount: 1 };
  }
};

export const qualityReviewer = async (state) => {
  if (state.finalReport) {
    return { isComplete: true, stepCount: 1 };
  }
  return { isComplete: false, stepCount: 1 };
};

import { StateGraph, END } from '@langchain/langgraph';
import { AgentState } from './state.js';
import {
  inputValidator,
  researchPlanner,
  dataGatherer,
  riskAssessor,
  reportSynthesizer,
  qualityReviewer
} from './nodes/index.js';

const routeAfterValidation = (state) => {
  if (state.errors.length > 0) return END;
  return 'planner';
};

const routeAfterReview = (state) => {
  if (state.stepCount > 15) return END;
  if (state.isComplete) return END;
  return 'synthesizer';
};

export const buildResearchGraph = () => {
  const workflow = new StateGraph(AgentState)
    .addNode('validator', inputValidator)
    .addNode('planner', researchPlanner)
    .addNode('gatherer', dataGatherer)
    .addNode('assessor', riskAssessor)
    .addNode('synthesizer', reportSynthesizer)
    .addNode('reviewer', qualityReviewer)

    .addEdge('__start__', 'validator')
    .addConditionalEdges('validator', routeAfterValidation, {
      planner: 'planner',
      [END]: END
    })
    .addEdge('planner', 'gatherer')
    .addEdge('gatherer', 'assessor')
    .addEdge('assessor', 'synthesizer')
    .addEdge('synthesizer', 'reviewer')
    .addConditionalEdges('reviewer', routeAfterReview, {
      synthesizer: 'synthesizer',
      [END]: END
    });

  return workflow.compile();
};

