import { buildResearchGraph } from '../agent/graph.js';

export const streamResearch = async (req, res) => {
  const sessionId = req.params.id;

  try {
    const session = await ResearchSession.findById(sessionId);
    if (!session || session.status !== 'PENDING') {
      res.write(`data: ${JSON.stringify({ error: 'Invalid session' })}\n\n`);
      return res.end();
    }

    session.status = 'RUNNING';
    await session.save();

    res.setHeader('Content-Type', 'text/event-stream');
    res.setHeader('Cache-Control', 'no-cache');
    res.setHeader('Connection', 'keep-alive');
    res.flushHeaders();

    const graph = buildResearchGraph();
    const initialState = { sessionId, ticker: session.ticker, query: session.query || '' };

    const stream = await graph.streamEvents(initialState, { version: 'v1' });

    for await (const event of stream) {
      const kind = event.event;
      if (kind === 'on_chat_model_stream') continue;

      let payload = null;
      if (kind === 'on_chain_start' && event.name !== 'LangGraph') {
        payload = { type: 'tool.calling', payload: { tool: event.name } };
      } else if (kind === 'on_chain_end' && event.name !== 'LangGraph') {
        payload = { type: 'tool.result', payload: { tool: event.name, status: 'success' } };
      }

      if (payload) {
        res.write(`data: ${JSON.stringify(payload)}\n\n`);
      }
    }

    const finalState = await graph.invoke(initialState);

    // Save report
    const reportData = finalState.finalReport;
    if (reportData) {
      await ResearchReport.create({
        session_id: sessionId,
        ticker: session.ticker,
        recommendation: reportData.recommendation,
        confidence_level: reportData.confidence_level,
        content: reportData
      });
      session.status = 'COMPLETED';
    } else {
      session.status = 'FAILED';
      session.error_message = 'Synthesis failed';
    }

    await session.save();

    res.write(`data: ${JSON.stringify({ type: 'session.completed', payload: { report: reportData } })}\n\n`);
    res.end();

  } catch (error) {
    console.error(error);
    await ResearchSession.findByIdAndUpdate(sessionId, { status: 'FAILED', error_message: error.message });
    res.write(`data: ${JSON.stringify({ type: 'session.error', payload: { error: error.message } })}\n\n`);
    res.end();
  }
};

