import { create } from 'zustand';
import axios from 'axios';

const API_BASE_URL = 'http://localhost:8000/api/research';

export const useResearchStore = create((set, get) => ({
  sessionId: null,
  ticker: null,
  status: 'IDLE', // IDLE, STARTING, RUNNING, COMPLETED, FAILED
  events: [],
  report: null,
  error: null,

  startSession: async (ticker) => {
    set({ status: 'STARTING', ticker, events: [], report: null, error: null });
    try {
      const res = await axios.post(API_BASE_URL, { ticker });
      set({ sessionId: res.data.session_id, status: 'RUNNING' });
    } catch (err) {
      set({ status: 'FAILED', error: err.response?.data?.error || err.message });
    }
  },

  processEvent: (event) => {
    set((state) => {
      const updatedEvents = [...state.events, event];

      if (event.type === 'session.completed') {
        return { events: updatedEvents, status: 'COMPLETED', report: event.payload.report };
      }
      if (event.type === 'session.error') {
        return { events: updatedEvents, status: 'FAILED', error: event.payload.error };
      }

      return { events: updatedEvents };
    });
  },

  reset: () => set({ sessionId: null, ticker: null, status: 'IDLE', events: [], report: null, error: null }),
}));

import React, { useEffect, useRef } from 'react';
import { useResearchStore } from '../store/researchStore';
import { Loader2, CheckCircle2, CircleDashed } from 'lucide-react';

const API_BASE_URL = 'http://localhost:8000/api/research';

export const AgentTrace = () => {
  const { sessionId, status, processEvent, events } = useResearchStore();
  const eventSourceRef = useRef(null);

  useEffect(() => {
    if (status !== 'RUNNING' || !sessionId) {
      if (eventSourceRef.current) {
        eventSourceRef.current.close();
        eventSourceRef.current = null;
      }
      return;
    }

    const sse = new EventSource(`${API_BASE_URL}/${sessionId}/stream`);
    eventSourceRef.current = sse;

    sse.onmessage = (e) => {
      try {
        const parsed = JSON.parse(e.data);
        processEvent(parsed);

        if (parsed.type === 'session.completed' || parsed.type === 'session.error') {
          sse.close();
        }
      } catch (err) {
        console.error('Failed to parse SSE event', err);
      }
    };

    sse.onerror = (error) => {
      console.error('SSE Error:', error);
      sse.close();
    };

    return () => {
      if (eventSourceRef.current) {
        eventSourceRef.current.close();
      }
    };
  }, [sessionId, status, processEvent]);

  if (status !== 'RUNNING' && status !== 'STARTING') return null;

  return (
    <div className="w-full max-w-2xl mx-auto p-6 bg-zinc-900 border border-zinc-800 rounded-lg shadow-xl mt-8">
      <div className="flex items-center gap-3 mb-6">
        <Loader2 className="h-5 w-5 text-emerald-500 animate-spin" />
        <h3 className="text-lg font-medium text-zinc-100">AI Agent Executing Research</h3>
      </div>

      <div className="space-y-4">
        {events.map((event, index) => {
          const isLatest = index === events.length - 1;
          return (
            <div key={index} className="flex gap-4">
              <div className="mt-1">
                {isLatest && status === 'RUNNING' ? (
                  <CircleDashed className="h-5 w-5 text-emerald-400 animate-spin" />
                ) : (
                  <CheckCircle2 className="h-5 w-5 text-zinc-500" />
                )}
              </div>
              <div>
                <p className={\`text-sm font-medium \${isLatest ? 'text-zinc-200' : 'text-zinc-500'}\`}>
                  {event.type === 'tool.calling' ? 'Executing Tool' : 'Processing...'}
                </p>
                {event.payload?.tool && (
                  <p className="text-xs text-zinc-400 font-mono mt-1">
                    > {event.payload.tool}
                  </p>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useResearchStore } from './store/researchStore';
import { AgentTrace } from './components/AgentTrace';

function App() {
  const [tickerInput, setTickerInput] = useState('');
  const { startSession, status, report, error } = useResearchStore();

  const handleSearch = (e) => {
    e.preventDefault();
    if (tickerInput.trim()) {
      startSession(tickerInput.trim());
    }
  };

  return (
    <div className="min-h-screen bg-black text-white p-8 font-sans">
      <div className="max-w-4xl mx-auto">
        <header className="mb-12 text-center">
          <h1 className="text-4xl font-bold mb-4 tracking-tight">AI Investment Research Agent</h1>
          <p className="text-zinc-400">Institutional-grade equity research in seconds.</p>
        </header>

        <form onSubmit={handleSearch} className="flex gap-4 max-w-md mx-auto mb-8">
          <input 
            type="text" 
            placeholder="Enter Ticker (e.g. AAPL)" 
            className="flex-1 bg-zinc-900 border border-zinc-800 rounded px-4 py-2 focus:outline-none focus:border-emerald-500 uppercase"
            value={tickerInput}
            onChange={(e) => setTickerInput(e.target.value)}
            disabled={status === 'RUNNING'}
          />
          <button 
            type="submit" 
            disabled={status === 'RUNNING'}
            className="bg-emerald-600 hover:bg-emerald-700 text-white px-6 py-2 rounded font-medium disabled:opacity-50"
          >
            Research
          </button>
        </form>

        {error && (
          <div className="bg-red-500/20 text-red-400 p-4 rounded-lg text-center mb-8 border border-red-500/50">
            {error}
          </div>
        )}

        <AgentTrace />

        {status === 'COMPLETED' && report && (
          <div className="mt-12 bg-zinc-900 p-8 rounded-lg border border-zinc-800 shadow-2xl animate-in fade-in duration-700">
            <div className="flex justify-between items-end border-b border-zinc-800 pb-6 mb-6">
              <h2 className="text-3xl font-bold text-white tracking-tight">Report Ready</h2>
              <span className="px-3 py-1 bg-emerald-500/20 text-emerald-400 font-bold rounded text-sm border border-emerald-500/50">
                {report.recommendation || 'BUY'}
              </span>
            </div>

            <div className="prose prose-invert max-w-none">
              <h3 className="text-xl text-emerald-400 mb-2">Executive Summary</h3>
              <p className="text-zinc-300 mb-6">{report.executive_summary}</p>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-8">
                <div>
                  <h3 className="text-xl text-emerald-400 mb-4">Financial Highlights</h3>
                  <div className="space-y-3">
                    {report.financial_highlights?.map((metric, i) => (
                      <div key={i} className="flex justify-between border-b border-zinc-800 pb-2">
                        <span className="text-zinc-400">{metric.metric_name}</span>
                        <div className="text-right">
                          <span className="block font-medium">{metric.value}</span>
                          <span className="text-xs text-emerald-500">{metric.context}</span>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                <div>
                  <h3 className="text-xl text-rose-400 mb-4">Risk Assessment</h3>
                  <ul className="space-y-2">
                    {report.risks?.map((risk, i) => (
                      <li key={i} className="text-sm text-zinc-300 bg-black p-3 rounded border border-zinc-800">
                        <span className="font-bold text-rose-400 block mb-1">{risk.severity} Severity - {risk.risk_type}</span>
                        {risk.description}
                      </li>
                    ))}
                  </ul>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;

