import { ChatGoogleGenerativeAI } from '@langchain/google-genai';
import { z } from 'zod';
import { SystemMessage, HumanMessage } from '@langchain/core/messages';
import { PLANNER_SYSTEM_PROMPT } from '../prompts/planner.js';
import logger from '../utils/logger.js';

// 1. Structured JSON Output Schema (Zod)
export const PlannerSchema = z.object({
  ticker: z.string().describe('The extracted stock ticker, max 5 uppercase letters'),
  is_valid: z.boolean().describe('True if the ticker is valid, false otherwise'),
  focus_areas: z.array(z.string()).describe('Specific areas the user wants researched'),
  error_message: z.string().nullable().describe('Error message if invalid or rejected')
});

/**
 * Executes the Planner Agent logic.
 * @param {string} userInput - The raw query from the user.
 * @returns {Promise<Object>} - The validated JSON output matching PlannerSchema.
 */
export const executePlannerAgent = async (userInput) => {
  const startTime = Date.now();
  logger.info({ action: 'planner_agent_start', query: userInput }, 'Planner Agent Execution Started');

  try {
    // 2. Metrics & Telemetry Callback
    const handleLLMEnd = (output) => {
      const tokenUsage = output.llmOutput?.estimatedTokenUsage || {};
      logger.info(
        { 
          action: 'planner_agent_metrics', 
          durationMs: Date.now() - startTime,
          promptTokens: tokenUsage.promptTokens || 0,
          completionTokens: tokenUsage.completionTokens || 0
        }, 
        'Planner Agent LLM Call Completed'
      );
    };

    // 3. LLM Setup with Zod Validation
    const llm = new ChatGoogleGenerativeAI({
      modelName: 'gemini-2.5-pro',
      temperature: 0, // Deterministic
      callbacks: [{ handleLLMEnd }]
    });

    // 4. Validation Binding & Retries
    // .withRetry() handles transient API failures automatically
    const structuredLlm = llm
      .withStructuredOutput(PlannerSchema, { name: 'PlannerResult' })
      .withRetry({ stopAfterAttempt: 3 });

    // 5. Tool Call (Execution)
    const result = await structuredLlm.invoke([
      new SystemMessage(PLANNER_SYSTEM_PROMPT),
      new HumanMessage(userInput)
    ]);

    logger.info({ action: 'planner_agent_success', result }, 'Planner Agent Execution Successful');
    return result;

  } catch (error) {
    // 6. Error Recovery & Fallbacks
    // If API is completely down after 3 retries, or output continually fails validation
    logger.error({ action: 'planner_agent_error', error: error.message }, 'Planner Agent Execution Failed');

    return {
      ticker: '',
      is_valid: false,
      focus_areas: [],
      error_message: `System Error: Unable to process request. (${error.message})`
    };
  }
};

