              <Loader2 className="w-5 h-5 animate-spin" />
            ) : (
              <>
                Analyze <ArrowRight className="w-5 h-5" />
              </>
            )}
          </motion.button>
        </div>
      </form>

      {error && (
        <motion.p 
          initial={{ opacity: 0, y: -10 }} 
          animate={{ opacity: 1, y: 0 }} 
          className="text-red-400 text-sm mt-4 bg-red-500/10 py-2 px-4 rounded-lg border border-red-500/20"
        >
          {error}
        </motion.p>
      )}
    </div>
  );
};

export default SearchBar;

import React, { useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useResearchStore } from '../store/researchStore';
import ProgressTimeline from '../components/ProgressTimeline';
import ReportDashboard from '../components/ReportDashboard';
import ErrorState from '../components/ErrorState';
import { ArrowLeft } from 'lucide-react';

const ReportView = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { status, processEvent, report, error, reset } = useResearchStore();

  useEffect(() => {
    // If we land here directly via URL, the status is IDLE, but we have an ID.
    // Realistically, the SSE endpoint would kick off the flow if it's pending.
    const API_BASE_URL = 'http://localhost:8000/api/v1/research';
    const sse = new EventSource(`${API_BASE_URL}/${id}/stream`);

    sse.onmessage = (e) => {
      try {
        const parsed = JSON.parse(e.data);
        processEvent(parsed);
        if (parsed.type === 'session.completed' || parsed.type === 'session.error') {
          sse.close();
        }
      } catch (err) {
        console.error('SSE Parse Error', err);
      }
    };

    sse.onerror = () => {
      sse.close();
      processEvent({ type: 'session.error', payload: { error: 'Connection lost to research agent.' } });
    };

    return () => {
      sse.close();
    };
  }, [id, processEvent]);

  const handleBack = () => {
    reset();
    navigate('/');
  };

  return (
    <div className="w-full animate-in fade-in duration-500">
      <button 
        onClick={handleBack}
        className="flex items-center gap-2 text-zinc-400 hover:text-white transition-colors mb-8"
      >
        <ArrowLeft className="w-4 h-4" /> Back to Search
      </button>

      {status === 'FAILED' ? (
        <ErrorState message={error} onRetry={handleBack} />
      ) : status === 'COMPLETED' && report ? (
        <ReportDashboard report={report} />
      ) : (
        <ProgressTimeline />
      )}
    </div>
  );
};

export default ReportView;

import React from 'react';
import { motion } from 'framer-motion';
import { useResearchStore } from '../store/researchStore';
import { CheckCircle2, CircleDashed, Server, BrainCircuit, Activity } from 'lucide-react';

const STAGES = [
  { id: 'planning', label: 'Planning Research Scope', icon: BrainCircuit },
  { id: 'gathering', label: 'Gathering Financials & News', icon: Server },
  { id: 'analyzing', label: 'Running Quantitative Analysis', icon: Activity },
  { id: 'synthesizing', label: 'Synthesizing Final Report', icon: BrainCircuit },
];

const ProgressTimeline = () => {
  const { events, status } = useResearchStore();

  // Basic mock mapping of events to stages for the UI
  // In a real app, the backend would send specific 'stage' markers
  const currentStageIndex = Math.min(Math.floor(events.length / 2), STAGES.length - 1);

  return (
    <div className="max-w-2xl mx-auto mt-12 bg-zinc-900/50 border border-zinc-800 rounded-2xl p-8 backdrop-blur-sm">
      <h2 className="text-xl font-bold mb-8 text-white flex items-center gap-3">
        <CircleDashed className="w-6 h-6 text-emerald-500 animate-spin" />
        Agent Executing...
      </h2>

      <div className="space-y-6 relative before:absolute before:inset-0 before:ml-3 before:-translate-x-px md:before:mx-auto md:before:translate-x-0 before:h-full before:w-0.5 before:bg-gradient-to-b before:from-transparent before:via-zinc-800 before:to-transparent">
        {STAGES.map((stage, index) => {
          const isCompleted = index < currentStageIndex;
          const isCurrent = index === currentStageIndex;
          const Icon = stage.icon;

          return (
            <motion.div 
              key={stage.id}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: index * 0.2 }}
              className="relative flex items-center justify-between md:justify-normal md:odd:flex-row-reverse group is-active"
            >
              <div className="flex items-center justify-center w-6 h-6 rounded-full border-4 border-black bg-zinc-800 text-zinc-500 shadow shrink-0 md:order-1 md:group-odd:-translate-x-1/2 md:group-even:translate-x-1/2 z-10 transition-colors duration-500">
                {isCompleted ? (
                  <CheckCircle2 className="w-6 h-6 text-emerald-500 absolute" />
                ) : isCurrent ? (
                  <div className="w-2 h-2 bg-emerald-400 rounded-full animate-ping" />
                ) : (
                  <div className="w-2 h-2 bg-zinc-600 rounded-full" />
                )}
              </div>
              <div className="w-[calc(100%-4rem)] md:w-[calc(50%-2.5rem)] p-4 rounded-xl border border-zinc-800 bg-zinc-900/80 shadow">
                <div className="flex items-center gap-3">
                  <Icon className={\`w-5 h-5 \${isCurrent ? 'text-emerald-400' : 'text-zinc-500'}\`} />
                  <span className={\`font-medium \${isCurrent ? 'text-white' : 'text-zinc-400'}\`}>{stage.label}</span>
                </div>
              </div>
            </motion.div>
          );
        })}
      </div>

      {/* Console output style logs */}
      <div className="mt-8 bg-black rounded-lg p-4 font-mono text-xs text-zinc-500 h-32 overflow-y-auto border border-zinc-800">
        {events.map((e, i) => (
          <div key={i} className="mb-1">
            <span className="text-emerald-500">[{new Date().toLocaleTimeString()}]</span> {e.type === 'tool.calling' ? \`Executing: \${e.payload?.tool}\` : \`Processing step...\`}
          </div>
        ))}
        {status === 'RUNNING' && <div className="animate-pulse">_</div>}
      </div>
    </div>
  );
};

