const ConfidenceMeter = ({ confidence }) => {
  const colors = {
    HIGH: 'bg-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.5)]',
    MEDIUM: 'bg-yellow-500 shadow-[0_0_15px_rgba(234,179,8,0.5)]',
    LOW: 'bg-red-500 shadow-[0_0_15px_rgba(239,68,68,0.5)]'
  };

  const texts = {
    HIGH: 'text-emerald-400',
    MEDIUM: 'text-yellow-400',
    LOW: 'text-red-400'
  };

  const currentLevel = confidence?.toUpperCase() || 'LOW';

  return (
    <div className="flex flex-col items-center">
      <div className="text-sm text-zinc-400 mb-2 font-medium tracking-wide uppercase">AI Confidence</div>
      <div className="flex gap-2 items-end h-8">
        <motion.div 
          initial={{ height: 0 }} animate={{ height: '40%' }} 
          className={\`w-3 rounded-t-sm \${currentLevel === 'LOW' ? colors.LOW : 'bg-zinc-800'}\`} 
        />
        <motion.div 
          initial={{ height: 0 }} animate={{ height: '70%' }} transition={{ delay: 0.1 }}
          className={\`w-3 rounded-t-sm \${['MEDIUM', 'HIGH'].includes(currentLevel) ? colors.MEDIUM : 'bg-zinc-800'}\`} 
        />
        <motion.div 
          initial={{ height: 0 }} animate={{ height: '100%' }} transition={{ delay: 0.2 }}
          className={\`w-3 rounded-t-sm \${currentLevel === 'HIGH' ? colors.HIGH : 'bg-zinc-800'}\`} 
        />
      </div>
      <div className={\`mt-2 font-bold text-lg \${texts[currentLevel]}\`}>{currentLevel}</div>
    </div>
  );
};

export default ConfidenceMeter;

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';

const FinancialCharts = ({ highlights }) => {
  // Convert highlights into chart data if applicable
  // Assuming highlight structure: { metric_name: "Revenue", value: "100M" }
  // In a real app, you'd want numerical data, but we'll adapt for visualization

  const data = highlights?.slice(0, 4).map(h => {
    // Attempt to extract numbers from strings like "15%" or "$2.5B"
    const num = parseFloat(h.value.replace(/[^0-9.-]+/g, ""));
    return {
      name: h.metric_name.substring(0, 15),
      value: isNaN(num) ? 0 : num,
      original: h.value
    };
  }) || [];

  return (
    <div className="h-[250px] w-full mt-4">
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data}>
          <CartesianGrid strokeDasharray="3 3" stroke="#27272a" vertical={false} />
          <XAxis dataKey="name" stroke="#a1a1aa" fontSize={12} tickLine={false} axisLine={false} />
          <YAxis stroke="#a1a1aa" fontSize={12} tickLine={false} axisLine={false} width={40} />
          <Tooltip 
            cursor={{ fill: '#27272a' }}
            contentStyle={{ backgroundColor: '#09090b', borderColor: '#27272a', borderRadius: '8px' }}
            formatter={(val, name, props) => [props.payload.original, "Value"]}
          />
          <Bar dataKey="value" fill="#10b981" radius={[4, 4, 0, 0]} />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

export default FinancialCharts;

