import React, { useState } from 'react';
import { Copy, Download, Check } from 'lucide-react';

const ActionToolbar = ({ report }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(JSON.stringify(report, null, 2));
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(report, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", \`\${report.ticker || 'research'}_report.json\`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  return (
    <div className="flex gap-2 bg-black border border-zinc-800 p-1 rounded-xl">
      <button 
        onClick={handleCopy}
        className="p-2 hover:bg-zinc-800 rounded-lg transition-colors text-zinc-400 hover:text-white"
        title="Copy JSON"
      >
        {copied ? <Check className="w-5 h-5 text-emerald-500" /> : <Copy className="w-5 h-5" />}
      </button>
      <div className="w-px bg-zinc-800 my-2"></div>
      <button 
        onClick={handleDownload}
        className="p-2 hover:bg-zinc-800 rounded-lg transition-colors text-zinc-400 hover:text-white"
        title="Download JSON"
      >
        <Download className="w-5 h-5" />
      </button>
    </div>
  );
};

export default ActionToolbar;

import React from 'react';
import { AlertCircle, RefreshCcw } from 'lucide-react';

const ErrorState = ({ message, onRetry }) => {
  return (
    <div className="flex flex-col items-center justify-center py-20 px-4 text-center">
      <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mb-6">
        <AlertCircle className="w-8 h-8 text-red-500" />
      </div>
      <h2 className="text-2xl font-bold text-white mb-2">Research Failed</h2>
      <p className="text-zinc-400 max-w-md mb-8">{message || "The AI encountered an unexpected error while gathering data or analyzing the stock."}</p>

      <button 
        onClick={onRetry}
        className="flex items-center gap-2 bg-zinc-800 hover:bg-zinc-700 text-white px-6 py-3 rounded-xl font-medium transition-colors"
      >
        <RefreshCcw className="w-4 h-4" /> Try Again
      </button>
    </div>
  );
};

export default ErrorState;

