import yahooFinance from 'yahoo-finance2';
import logger from '../utils/logger.js';

/**
 * Scrapes financial data and news from Yahoo Finance.
 * Implements a circuit breaker / fallback to prevent crashes if the API is down.
 */
export const fetchCompanyData = async (ticker) => {
  logger.info({ ticker }, 'Fetching data from Yahoo Finance...');

  try {
    // Suppress console notices from yahoo-finance2
    yahooFinance.suppressNotices(['yahooSurvey']);

    const [quote, quoteSummary, searchResults] = await Promise.all([
      yahooFinance.quote(ticker).catch(() => null),
      yahooFinance.quoteSummary(ticker, { 
        modules: ['financialData', 'defaultKeyStatistics', 'summaryProfile'] 
      }).catch(() => null),
      yahooFinance.search(ticker, { newsCount: 10 }).catch(() => ({ news: [] }))
    ]);

    if (!quote && !quoteSummary) {
      throw new Error('No financial data found for ticker.');
    }

    const financials = {
      price: quote?.regularMarketPrice || null,
      marketCap: quote?.marketCap || null,
      revenue: quoteSummary?.financialData?.totalRevenue || null,
      netIncome: quoteSummary?.financialData?.netIncomeToCommon || null,
      profitMargins: quoteSummary?.financialData?.profitMargins || null,
      operatingMargins: quoteSummary?.financialData?.operatingMargins || null,
      freeCashflow: quoteSummary?.financialData?.freeCashflow || null,
      totalDebt: quoteSummary?.financialData?.totalDebt || null,
      debtToEquity: quoteSummary?.financialData?.debtToEquity || null,
      peRatio: quoteSummary?.defaultKeyStatistics?.forwardPE || quote?.trailingPE || null,
      pbRatio: quoteSummary?.defaultKeyStatistics?.priceToBook || null,
      industry: quoteSummary?.summaryProfile?.industry || 'Unknown',
      sector: quoteSummary?.summaryProfile?.sector || 'Unknown'
    };

    const news = searchResults.news.map(article => ({
      title: article.title,
      publisher: article.publisher,
      link: article.link
    }));

    return { financials, news };
  } catch (error) {
    logger.error({ ticker, error: error.message }, 'Yahoo Finance API Failed');
    return {
      financials: null,
      news: [],
      error: error.message
    };
  }
};

import { Annotation } from '@langchain/langgraph';

// Custom reducer to append arrays instead of overwriting
const appendReducer = (a, b) => (a || []).concat(b || []);

export const AgentState = Annotation.Root({
  sessionId: Annotation.String,
  ticker: Annotation.String,
  query: Annotation.String,
  is_valid: Annotation.Boolean,

  // Raw Data
  financialData: Annotation.Any,
  newsData: Annotation.Any,

  // Analysis
  analysis_financial: Annotation.Any,
  analysis_news: Annotation.Any,
  analysis_risk: Annotation.Any,
  decision: Annotation.Any,

  // Output
  finalReport: Annotation.Any,
  errors: Annotation({ reducer: appendReducer, default: () => [] }),
  stepCount: Annotation({ reducer: (x, y) => x + y, default: () => 0 })
});

import { fetchCompanyData } from '../tools/yahooFinance.js';

export const executeResearchAgent = async (state) => {
  if (!state.is_valid) return { stepCount: 1 };

  const data = await fetchCompanyData(state.ticker);

  if (data.error) {
    return {
      financialData: null,
      newsData: [],
      errors: [data.error],
      stepCount: 1
    };
  }

  return {
    financialData: data.financials,
    newsData: data.news,
    stepCount: 1
  };
};

import { ChatGoogleGenerativeAI } from '@langchain/google-genai';
import { z } from 'zod';
import { SystemMessage, HumanMessage } from '@langchain/core/messages';
import { FINANCIAL_PROMPT } from '../prompts/agents.js';

export const FinancialSchema = z.object({
  financial_health_score: z.number().min(1).max(10),
  key_strengths: z.array(z.string()),
  key_weaknesses: z.array(z.string()),
  summary: z.string()
});

export const executeFinancialAgent = async (state) => {
  if (!state.financialData) {
    return { analysis_financial: { financial_health_score: 0, summary: "No financial data available.", key_strengths: [], key_weaknesses: [] }, stepCount: 1 };
  }

  const llm = new ChatGoogleGenerativeAI({ modelName: 'gemini-2.5-pro', temperature: 0 })
    .withStructuredOutput(FinancialSchema, { name: 'FinancialAnalysis' })
    .withRetry({ stopAfterAttempt: 3 });

  try {
    const result = await llm.invoke([
      new SystemMessage(FINANCIAL_PROMPT),
      new HumanMessage(JSON.stringify(state.financialData))
    ]);
    return { analysis_financial: result, stepCount: 1 };
  } catch (error) {
    return { analysis_financial: { financial_health_score: 0, summary: "Analysis failed.", key_strengths: [], key_weaknesses: [] }, errors: [error.message], stepCount: 1 };
  }
};

import { ChatGoogleGenerativeAI } from '@langchain/google-genai';
import { z } from 'zod';
import { SystemMessage, HumanMessage } from '@langchain/core/messages';
import { NEWS_PROMPT } from '../prompts/agents.js';

export const NewsSchema = z.object({
  sentiment: z.enum(['POSITIVE', 'NEUTRAL', 'NEGATIVE']),
  major_events: z.array(z.string()),
  sentiment_summary: z.string()
});

export const executeNewsAgent = async (state) => {
  if (!state.newsData || state.newsData.length === 0) {
    return { analysis_news: { sentiment: 'NEUTRAL', sentiment_summary: "No recent news available.", major_events: [] }, stepCount: 1 };
  }

  const llm = new ChatGoogleGenerativeAI({ modelName: 'gemini-2.5-pro', temperature: 0 })
    .withStructuredOutput(NewsSchema, { name: 'NewsAnalysis' })
    .withRetry({ stopAfterAttempt: 3 });

  try {
    const result = await llm.invoke([
      new SystemMessage(NEWS_PROMPT),
      new HumanMessage(JSON.stringify(state.newsData))
    ]);
    return { analysis_news: result, stepCount: 1 };
  } catch (error) {
    return { analysis_news: { sentiment: 'NEUTRAL', sentiment_summary: "Analysis failed.", major_events: [] }, errors: [error.message], stepCount: 1 };
  }
};

import { ChatGoogleGenerativeAI } from '@langchain/google-genai';
import { z } from 'zod';
import { SystemMessage, HumanMessage } from '@langchain/core/messages';
import { RISK_PROMPT } from '../prompts/agents.js';

export const RiskSchema = z.object({
  macro_risks: z.array(z.string()),
  micro_risks: z.array(z.string()),
  bear_case_summary: z.string(),
