    .withRetry({ stopAfterAttempt: 3 });

  try {
    const result = await llm.invoke([
      new SystemMessage(RISK_PROMPT),
      new HumanMessage(context)
    ]);
    return { analysis_risk: result, stepCount: 1 };
  } catch (error) {
    return { analysis_risk: { overall_risk_level: 'HIGH', bear_case_summary: "Risk analysis failed.", macro_risks: [], micro_risks: [] }, errors: [error.message], stepCount: 1 };
  }
};

import { ChatGoogleGenerativeAI } from '@langchain/google-genai';
import { z } from 'zod';
import { SystemMessage, HumanMessage } from '@langchain/core/messages';
import { DECISION_PROMPT } from '../prompts/agents.js';

export const DecisionSchema = z.object({
  recommendation: z.enum(['BUY', 'HOLD', 'SELL']),
  confidence: z.enum(['HIGH', 'MEDIUM', 'LOW']),
  justification: z.string()
});

export const executeDecisionAgent = async (state) => {
  const context = JSON.stringify({
    financial: state.analysis_financial,
    news: state.analysis_news,
    risk: state.analysis_risk
  });

  const llm = new ChatGoogleGenerativeAI({ modelName: 'gemini-2.5-pro', temperature: 0 })
    .withStructuredOutput(DecisionSchema, { name: 'DecisionAnalysis' })
    .withRetry({ stopAfterAttempt: 3 });

  try {
    const result = await llm.invoke([
      new SystemMessage(DECISION_PROMPT),
      new HumanMessage(context)
    ]);
    return { decision: result, stepCount: 1 };
  } catch (error) {
    return { decision: { recommendation: 'HOLD', confidence: 'LOW', justification: "Decision engine failed." }, errors: [error.message], stepCount: 1 };
  }
};

import { ChatGoogleGenerativeAI } from '@langchain/google-genai';
import { z } from 'zod';
import { SystemMessage, HumanMessage } from '@langchain/core/messages';
import { SYNTHESIZER_PROMPT } from '../prompts/agents.js';

export const FinalReportSchema = z.object({
  ticker: z.string(),
  executive_summary: z.string(),
  company_overview: z.string(),
  financial_highlights: z.array(z.object({
    metric_name: z.string(),
    value: z.string(),
    context: z.string()
  })),
  risks: z.array(z.object({
    risk_type: z.string(),
    description: z.string(),
    severity: z.enum(['High', 'Medium', 'Low'])
  })),
  bull_case: z.array(z.string()),
  bear_case: z.array(z.string()),
  recommendation: z.enum(['BUY', 'HOLD', 'SELL']),
  confidence_level: z.enum(['HIGH', 'MEDIUM', 'LOW'])
});

export const executeSynthesizerAgent = async (state) => {
  // If the planner rejected the ticker, return a clean error report
  if (!state.is_valid) {
    return { finalReport: null };
  }

  const context = JSON.stringify({
    ticker: state.ticker,
    financial: state.analysis_financial,
    news: state.analysis_news,
    risk: state.analysis_risk,
    decision: state.decision
  });

  const llm = new ChatGoogleGenerativeAI({ modelName: 'gemini-2.5-pro', temperature: 0 })
    .withStructuredOutput(FinalReportSchema, { name: 'FinalReport' })
    .withRetry({ stopAfterAttempt: 3 });

  try {
    const result = await llm.invoke([
      new SystemMessage(SYNTHESIZER_PROMPT),
      new HumanMessage(context)
    ]);
    return { finalReport: result, stepCount: 1 };
  } catch (error) {
    return { errors: [error.message], stepCount: 1, finalReport: null };
  }
};

import { StateGraph, START, END } from '@langchain/langgraph';
import { AgentState } from './state.js';
import { executePlannerAgent } from '../agents/plannerAgent.js';
import { executeResearchAgent } from '../agents/researchAgent.js';
import { executeFinancialAgent } from '../agents/financialAgent.js';
import { executeNewsAgent } from '../agents/newsAgent.js';
import { executeRiskAgent } from '../agents/riskAgent.js';
import { executeDecisionAgent } from '../agents/decisionAgent.js';
import { executeSynthesizerAgent } from '../agents/synthesizerAgent.js';

/**
 * Builds and compiles the LangGraph State Machine.
 */
export const buildResearchGraph = () => {
  const workflow = new StateGraph(AgentState)
    .addNode('planner', executePlannerAgent)
    .addNode('research', executeResearchAgent)
    .addNode('financial', executeFinancialAgent)
    .addNode('news', executeNewsAgent)
    .addNode('risk', executeRiskAgent)
    .addNode('decision', executeDecisionAgent)
    .addNode('synthesizer', executeSynthesizerAgent);

  // Edges
  workflow.addEdge(START, 'planner');

  // Conditional routing after planner
  workflow.addConditionalEdges('planner', (state) => {
    return state.is_valid ? 'valid' : 'invalid';
  }, {
    valid: 'research',
    invalid: 'synthesizer' // Skip to output error
  });

  // Parallel Execution: Financial and News happen after Research
  // In LangGraph JS, a single node can flow into multiple nodes.
  workflow.addEdge('research', 'financial');
  workflow.addEdge('research', 'news');

  // Risk assesses both financial and news
  workflow.addEdge('financial', 'risk');
  workflow.addEdge('news', 'risk');

  workflow.addEdge('risk', 'decision');
  workflow.addEdge('decision', 'synthesizer');
  workflow.addEdge('synthesizer', END);

  return workflow.compile();
};

import InvestmentReport from '../models/InvestmentReport.js';
import SearchHistory from '../models/SearchHistory.js';
import { buildResearchGraph } from '../graph/graph.js';
import logger from '../utils/logger.js';
import mongoose from 'mongoose';

export const createResearchSession = async (ticker, query) => {
  const sessionId = new mongoose.Types.ObjectId();

  await SearchHistory.create({
    ticker,
    query
  });

  return sessionId.toString();
};

export const runGraphAndStream = async (sessionId, ticker, res) => {
  const graph = buildResearchGraph();
  const initialState = { sessionId, ticker, query: '' };

  try {
    const stream = await graph.streamEvents(initialState, { version: 'v1' });

    for await (const event of stream) {
      if (event.event === 'on_chain_start' && event.name !== 'LangGraph') {
        res.write(\`data: \${JSON.stringify({ type: 'tool.calling', payload: { tool: event.name } })}\\n\\n\`);
      }
    }

    const finalState = await graph.invoke(initialState);

    if (finalState.finalReport) {
      const report = await InvestmentReport.create({
        sessionId,
        ticker,
        recommendation: finalState.finalReport.recommendation || 'HOLD',
        confidence: finalState.finalReport.confidence_level || 'LOW',
        content: finalState.finalReport
      });
      res.write(\`data: \${JSON.stringify({ type: 'session.completed', payload: { report: finalState.finalReport } })}\\n\\n\`);
    } else {
      res.write(\`data: \${JSON.stringify({ type: 'session.error', payload: { error: 'Synthesis failed or invalid ticker.' } })}\\n\\n\`);
    }
    res.end();

  } catch (error) {
    logger.error(error);
    res.write(\`data: \${JSON.stringify({ type: 'session.error', payload: { error: error.message } })}\\n\\n\`);
    res.end();
  }
};

import { createResearchSession, runGraphAndStream } from '../services/researchService.js';
import InvestmentReport from '../models/InvestmentReport.js';

export const startResearch = async (req, res) => {
  const { ticker, query } = req.body;
  const sessionId = await createResearchSession(ticker, query);

  res.status(202).json({
    status: 'success',
    data: { session_id: sessionId }
  });
};

export const streamResearch = async (req, res) => {
  const { id } = req.params;
  const { ticker } = req.query; // Ticker passed as query param for the stream

  res.setHeader('Content-Type', 'text/event-stream');
  res.setHeader('Cache-Control', 'no-cache');
  res.setHeader('Connection', 'keep-alive');
  res.flushHeaders();

  await runGraphAndStream(id, ticker || 'AAPL', res);
};

export const getReport = async (req, res) => {
  const report = await InvestmentReport.findOne({ sessionId: req.params.id });
  if (!report) {
    return res.status(404).json({ status: 'error', error: { message: 'Report not found' } });
  }
  res.status(200).json({ status: 'success', data: report });
};

import express from 'express';
import Joi from 'joi';
import { validate } from '../middleware/validate.js';
import {
  startResearch,
  getReport,
  streamResearch,
} from '../controllers/researchController.js';

const router = express.Router();

const researchRequestSchema = {
  ticker: Joi.string().trim().uppercase().max(10).required(),
  query: Joi.string().trim().max(500).optional().allow(''),
};

router.post('/', validate(researchRequestSchema), startResearch);
router.get('/:id', getReport);
router.get('/:id/stream', streamResearch);

export default router;

