import React from 'react';
import ConfidenceMeter from './ConfidenceMeter';
import FinancialCharts from './FinancialCharts';
import ActionToolbar from './ActionToolbar';
import { motion, AnimatePresence } from 'framer-motion';
import { AlertTriangle, TrendingUp, ShieldAlert, Sparkles } from 'lucide-react';
import { useResearchStore } from '../store/researchStore';

const ReportDashboard = () => {
  const { report, partialReport, status } = useResearchStore();

  // If report exists, use it. Otherwise seamlessly map the incremental state to create a streaming effect!
  const data = report || {
    ticker: partialReport.ticker,
    executive_summary: partialReport.analysis_financial?.summary,
    bull_case: partialReport.analysis_financial?.key_strengths,
    bear_case: partialReport.analysis_risk?.macro_risks,
    financial_highlights: partialReport.analysis_financial ? [
      { metric_name: "Health Score", value: `${partialReport.analysis_financial.financial_health_score}/10`, context: "AI Derived" }
    ] : null,
    risks: partialReport.analysis_risk?.micro_risks?.map(r => ({ risk_type: "Operational", severity: "High", description: r })),
    competitors: [],
    sources: [],
    recommendation: partialReport.decision?.recommendation,
    confidence_level: partialReport.decision?.confidence
  };

  if (!data || Object.keys(data).length === 0 || (!report && !partialReport.analysis_financial)) return null;

