import { createResearchSession, runGraphAndStream, getReportHistory as fetchHistory, getReportBySessionId } from '../services/researchService.js';
import { streamChatResponse } from '../services/chatService.js';
import InvestmentReport from '../models/InvestmentReport.js';

export const startResearch = async (req, res) => {
  const { ticker, query } = req.body;
  const sessionId = await createResearchSession(ticker, query);

  res.status(202).json({
    status: 'success',
    data: { session_id: sessionId }
  });
};

export const streamResearch = async (req, res) => {
  const { id } = req.params;
  const { ticker } = req.query;

  res.setHeader('Content-Type', 'text/event-stream');
  res.setHeader('Cache-Control', 'no-cache');
  res.setHeader('Connection', 'keep-alive');
  res.setHeader('X-Accel-Buffering', 'no');
  res.flushHeaders();

  await runGraphAndStream(id, ticker || 'AAPL', res);
};

export const getReport = async (req, res) => {
  const report = await InvestmentReport.findOne({ sessionId: req.params.id });
  if (!report) {
    return res.status(404).json({ status: 'error', error: { message: 'Report not found' } });
  }
  res.status(200).json({ status: 'success', data: report });
};

export const getReportHistory = async (req, res) => {
  try {
    const history = await fetchHistory();
    res.status(200).json({ status: 'success', data: history });
  } catch (error) {
    res.status(500).json({ status: 'error', error: { message: error.message } });
  }
};

export const chatWithReport = async (req, res) => {
  const { id } = req.params;
  const { messages } = req.body;

  const reportDoc = await getReportBySessionId(id);
  if (!reportDoc) {
    return res.status(404).json({ status: 'error', error: { message: 'Report not found for chat' } });
  }

  res.setHeader('Content-Type', 'text/event-stream');
  res.setHeader('Cache-Control', 'no-cache');
  res.setHeader('Connection', 'keep-alive');
  res.setHeader('X-Accel-Buffering', 'no');
  res.flushHeaders();

  await streamChatResponse(reportDoc.content, messages || [], res);
};

import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export const useThemeStore = create(
  persist(
    (set, get) => ({
      theme: 'dark', // 'dark' | 'light'
      toggleTheme: () => {
        const next = get().theme === 'dark' ? 'light' : 'dark';
        set({ theme: next });
        document.documentElement.classList.toggle('light', next === 'light');
      },
      initTheme: () => {
        const t = get().theme;
        document.documentElement.classList.toggle('light', t === 'light');
      }
    }),
    { name: 'ag-theme' }
  )
);

export const useWatchlistStore = create(
  persist(
    (set, get) => ({
      watchlist: [],
      toggle: (ticker) => {
        const list = get().watchlist;
        const exists = list.includes(ticker.toUpperCase());
        set({ watchlist: exists ? list.filter(t => t !== ticker.toUpperCase()) : [...list, ticker.toUpperCase()] });
      },
      isWatched: (ticker) => get().watchlist.includes(ticker?.toUpperCase()),
    }),
    { name: 'ag-watchlist' }
  )
);

import { create } from 'zustand';

const API_BASE = 'http://localhost:8000/api/v1/research';

export const useChatStore = create((set, get) => ({
  messages: [],
  isStreaming: false,

  addUserMessage: (content) => {
    set(state => ({ messages: [...state.messages, { role: 'user', content, id: Date.now() }] }));
  },

  streamResponse: async (sessionId) => {
    const messages = get().messages;
    set({ isStreaming: true });

    const aiMsgId = Date.now();
    set(state => ({ messages: [...state.messages, { role: 'ai', content: '', id: aiMsgId }] }));

    try {
      const res = await fetch(`${API_BASE}/${sessionId}/chat`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ messages: messages.map(m => ({ role: m.role, content: m.content })) }),
      });

      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let buffer = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n\n');
        buffer = lines.pop();

        for (const line of lines) {
          if (line.startsWith('data: ')) {
            try {
              const event = JSON.parse(line.slice(6));
              if (event.type === 'chat.chunk') {
                set(state => ({
                  messages: state.messages.map(m =>
                    m.id === aiMsgId ? { ...m, content: m.content + event.payload.text } : m
                  )
                }));
              }
              if (event.type === 'chat.done' || event.type === 'chat.error') {
                break;
              }
            } catch {}
          }
        }
      }
    } catch (e) {
      set(state => ({
        messages: state.messages.map(m =>
          m.id === aiMsgId ? { ...m, content: 'Sorry, I encountered an error. Please try again.' } : m
        )
      }));
    }
    set({ isStreaming: false });
  },

  reset: () => set({ messages: [], isStreaming: false }),
}));

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, Bot, User, Loader2, Sparkles, X } from 'lucide-react';
import { useChatStore } from '../store/chatStore';
import { useResearchStore } from '../store/researchStore';

const QUICK_QUESTIONS = [
  'Why did you give this recommendation?',
  'What are the biggest risks?',
  'How does it compare to competitors?',
  'Is this good for long-term investing?',
  'Explain the P/E ratio for this stock',
];

const ChatMessage = ({ message }) => {
  const isAI = message.role === 'ai';
  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      className={`flex gap-3 ${isAI ? 'items-start' : 'items-start flex-row-reverse'}`}
    >
      <div className={`w-7 h-7 rounded-full flex items-center justify-center shrink-0 ${isAI ? 'bg-emerald-500/20 text-emerald-400' : 'bg-zinc-700 text-zinc-300'}`}>
        {isAI ? <Bot className="w-4 h-4" /> : <User className="w-4 h-4" />}
      </div>
      <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm leading-relaxed whitespace-pre-wrap ${
        isAI 
          ? 'bg-zinc-800/80 text-zinc-200 rounded-tl-sm border border-zinc-700/50' 
          : 'bg-emerald-600 text-white rounded-tr-sm'
      }`}>
        {message.content || <span className="flex items-center gap-1 text-zinc-400">
          <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
          <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
          <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
        </span>}
      </div>
    </motion.div>
  );
};

const ChatSidebar = () => {
  const [input, setInput] = useState('');
  const { messages, isStreaming, addUserMessage, streamResponse, reset } = useChatStore();
  const { sessionId } = useResearchStore();
  const bottomRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMessage = async (text) => {
    const msg = text || input.trim();
    if (!msg || isStreaming) return;
    setInput('');
    addUserMessage(msg);
    await streamResponse(sessionId);
  };

  return (
    <div className="flex flex-col h-full bg-zinc-950 border-l border-zinc-800 rounded-r-2xl overflow-hidden">
      {/* Header */}
      <div className="px-5 py-4 border-b border-zinc-800 bg-black/30 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-emerald-500/30 to-cyan-500/30 border border-emerald-500/30 flex items-center justify-center">
            <Sparkles className="w-4 h-4 text-emerald-400" />
          </div>
          <div>
            <h3 className="font-bold text-sm text-white">AI Analyst</h3>
            <p className="text-[10px] text-zinc-500">Ask anything about this report</p>
          </div>
        </div>
        <button onClick={reset} className="text-zinc-600 hover:text-zinc-400 text-[10px] transition-colors">Clear</button>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-thin scrollbar-thumb-zinc-800">
        {messages.length === 0 && (
          <div className="space-y-3 mt-4">
            <p className="text-zinc-500 text-xs text-center mb-4">Quick questions to get started:</p>
            {QUICK_QUESTIONS.map((q, i) => (
              <motion.button
                key={i}
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: i * 0.05 }}
                onClick={() => sendMessage(q)}
                className="w-full text-left text-xs text-zinc-400 bg-zinc-900 border border-zinc-800 hover:border-emerald-500/40 hover:text-emerald-400 px-4 py-2.5 rounded-xl transition-all"
              >
                {q}
              </motion.button>
            ))}
          </div>
        )}
        <AnimatePresence>
          {messages.map((msg) => <ChatMessage key={msg.id} message={msg} />)}
        </AnimatePresence>
        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <div className="p-3 border-t border-zinc-800 bg-black/20 shrink-0">
        <form onSubmit={(e) => { e.preventDefault(); sendMessage(); }} className="flex gap-2">
          <input
            ref={inputRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask about this report..."
            disabled={isStreaming || !sessionId}
            className="flex-1 bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-2.5 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-emerald-500/50 disabled:opacity-50"
          />
          <button
            type="submit"
            disabled={!input.trim() || isStreaming || !sessionId}
            className="w-10 h-10 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 rounded-xl flex items-center justify-center transition-colors shrink-0"
          >
            {isStreaming ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatSidebar;

import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { TrendingUp, TrendingDown, ArrowRight, Clock, Heart, ExternalLink, MessageSquare } from 'lucide-react';
