import React, { useEffect, useState } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { useResearchStore } from '../store/researchStore';
import { useChatStore } from '../store/chatStore';
import { useWatchlistStore } from '../store/uiStore';
import ProgressTimeline from '../components/ProgressTimeline';
import ReportDashboard from '../components/ReportDashboard';
import ChatSidebar from '../components/ChatSidebar';
import ErrorState from '../components/ErrorState';
import { ArrowLeft, Heart, MessageSquare, X } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const ReportView = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const location = useLocation();
  const { status, processEvent, report, error, reset, ticker } = useResearchStore();
  const { reset: resetChat } = useChatStore();
  const { isWatched, toggle } = useWatchlistStore();
  const [chatOpen, setChatOpen] = useState(false);

  useEffect(() => {
    resetChat();
    const API_BASE_URL = 'http://localhost:8000/api/v1/research';
    const sse = new EventSource(`${API_BASE_URL}/${id}/stream?ticker=${ticker || 'AAPL'}`);

    sse.onmessage = (e) => {
      try {
        const parsed = JSON.parse(e.data);
        processEvent(parsed);
        if (parsed.type === 'session.completed' || parsed.type === 'session.error') {
          sse.close();
        }
      } catch (err) {
        console.error('SSE Parse Error', err);
      }
    };

    sse.onerror = () => {
      sse.close();
      if (status !== 'COMPLETED') {
        processEvent({ type: 'session.error', payload: { error: 'Connection to research agent was lost.' } });
      }
    };

    return () => sse.close();
  }, [id]);

  const handleBack = () => {
    reset();
    navigate('/');
  };

  const isCompleted = status === 'COMPLETED';
  const currentTicker = report?.ticker || ticker;

  return (
    <div className="w-full">
      {/* Top bar */}
      <div className="flex items-center justify-between mb-6">
        <button
          onClick={handleBack}
          className="flex items-center gap-2 text-zinc-400 hover:text-white transition-colors text-sm"
        >
          <ArrowLeft className="w-4 h-4" /> Back to Search
        </button>

        {currentTicker && (
          <div className="flex items-center gap-2">
            {isCompleted && (
              <>
                <button
                  onClick={() => toggle(currentTicker)}
                  className={`flex items-center gap-1.5 px-3 py-1.5 rounded-xl border text-sm font-medium transition-all ${
                    isWatched(currentTicker)
                      ? 'text-red-400 bg-red-500/10 border-red-500/30'
                      : 'text-zinc-400 bg-zinc-900 border-zinc-800 hover:text-red-400 hover:border-red-500/30'
                  }`}
                >
                  <Heart className={`w-3.5 h-3.5 ${isWatched(currentTicker) ? 'fill-current' : ''}`} />
                  {isWatched(currentTicker) ? 'Watching' : 'Watch'}
                </button>
                <button
                  onClick={() => setChatOpen(v => !v)}
                  className={`flex items-center gap-1.5 px-3 py-1.5 rounded-xl border text-sm font-medium transition-all ${
                    chatOpen
                      ? 'text-emerald-400 bg-emerald-500/10 border-emerald-500/30'
                      : 'text-zinc-400 bg-zinc-900 border-zinc-800 hover:text-emerald-400 hover:border-emerald-500/30'
                  }`}
                >
                  <MessageSquare className="w-3.5 h-3.5" />
                  {chatOpen ? 'Close Chat' : 'Ask AI'}
                </button>
              </>
            )}
          </div>
        )}
      </div>

      {/* Main content */}
      {status === 'FAILED' ? (
        <ErrorState message={error} onRetry={handleBack} />
      ) : (
        <div className={`flex gap-6 transition-all duration-300 ${chatOpen ? '' : ''}`}>
          {/* Report column */}
          <div className={`transition-all duration-300 ${chatOpen ? 'w-full lg:w-[65%]' : 'w-full'}`}>
            <div className="space-y-8">
              {status !== 'COMPLETED' && <ProgressTimeline />}
              <ReportDashboard />
            </div>
          </div>

          {/* Chat sidebar */}
          <AnimatePresence>
            {chatOpen && (
              <motion.div
                initial={{ opacity: 0, width: 0 }}
                animate={{ opacity: 1, width: '35%' }}
                exit={{ opacity: 0, width: 0 }}
                transition={{ type: 'spring', stiffness: 300, damping: 30 }}
                className="hidden lg:block shrink-0 h-[80vh] sticky top-20"
              >
                <ChatSidebar />
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      )}

      {/* Mobile chat drawer */}
      <AnimatePresence>
        {chatOpen && (
          <motion.div
            initial={{ y: '100%' }} animate={{ y: 0 }} exit={{ y: '100%' }}
            className="fixed inset-x-0 bottom-0 h-[70vh] z-50 lg:hidden shadow-2xl"
          >
            <button
              onClick={() => setChatOpen(false)}
              className="absolute top-3 right-3 z-10 text-zinc-400 hover:text-white"
            >
              <X className="w-5 h-5" />
            </button>
            <ChatSidebar />
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

