export const exportToPDF = (elementId, filename = 'report.pdf') => {
  // Use native browser print which handles modern CSS (Grid, Flex, backdrop-filter, SVG) perfectly.
  // Add print-specific CSS in index.css to hide sidebar, navbars, and chat when printing.

  // Optional: Set document title to filename temporarily so the default saved PDF name matches
  const originalTitle = document.title;
  document.title = filename.replace('.pdf', '');

  window.print();

  // Restore original title
  document.title = originalTitle;
};

