import html2pdf from 'html2pdf.js';

export const exportToPDF = async (elementId, filename = 'report.pdf') => {
  const element = document.getElementById(elementId);
  if (!element) return;

  // Temporarily hide elements we don't want in the PDF using a specific class
  const hiddenElements = element.querySelectorAll('.hide-on-print');
  hiddenElements.forEach(el => el.style.display = 'none');

  const opt = {
    margin:       [10, 10, 10, 10],
    filename:     filename,
    image:        { type: 'jpeg', quality: 1 },
    html2canvas:  { 
      scale: 2, 
      useCORS: true, 
      logging: false,
      backgroundColor: '#0A0A0A', // Force dark background
      ignoreElements: (node) => {
        // Ignore decorative blur elements that crash html2canvas
        return node.classList && node.classList.contains('blur-3xl');
      }
    },
    jsPDF:        { unit: 'mm', format: 'a4', orientation: 'portrait' }
  };

  try {
    await html2pdf().set(opt).from(element).save();
  } catch (error) {
    console.error("PDF Export failed", error);
  } finally {
    // Restore elements
    hiddenElements.forEach(el => el.style.display = '');
  }
};

